var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"할아범! 괜찮아?!","JPN":"おじいちゃん！　大丈夫！？","ENG":"Kian! Are you all right?!","TWN":"奇恩爺爺！你沒事吧？！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"전 무사합니다, 아가씨.","JPN":"私は大丈夫です、お嬢様。","ENG":"I'm fine, Miss Morgana.","TWN":"小姐，我沒事。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"이거, 또 신세를 지고 말았군요.","JPN":"これは、またお手数をかけてしまいましたね。","ENG":"It seems that you saved my life again.","TWN":"我又給小姐添麻煩了。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"알고 있으면 혼자 있을 땐 조심 좀 해!","JPN":"そう思うなら、一人のときは気を付けてよね！","ENG":"If you're really grateful, then don't let your guard down when you're alone!","TWN":"知道就好，一個人的時候拜託你小心點！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"이번 원정에서 할아범이 죽기라도 하면 그건 다 내 탓이니까!","JPN":"この遠征でおじいちゃんが死んだら、すべての責任はあたしが負うんだから！","ENG":"Because it'll be my fault if you die on this expedition!","TWN":"要是奇恩爺爺在這次的遠征中死掉的話，那全都是我的錯！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L9_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"앞으론 더 조심하겠습니다.","JPN":"今後は、より一層気をつけます。","ENG":"I'll be more careful next time.","TWN":"我以後會更小心的。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"…흥.","JPN":"……ふん。","ENG":"...Hmph.","TWN":"…哼。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그래서, 뭣 때문에 이런 곳에 혼자 남아있던 거야?","JPN":"それで、いったいどうしてこんなところに一人で残っていたわけ？","ENG":"So, what were you doing here all by yourself?","TWN":"我問你，你為什麼會一個人在這裡？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"창고에서 멀쩡한 수레 바퀴를 찾아 나르고 있었는데…","JPN":"倉庫で丈夫そうな車輪を見つけまして、それを運んでいたところ……","ENG":"I found a fine wheel in the warehouse and tried to move it...","TWN":"我在倉庫找到可以用的車輪，想說把它搬過去…"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"저 눈더미 속에서 작은 빛이 보이더군요.","JPN":"あの雪の山の内側からかすかな光が見えまして。","ENG":"But then, I saw this glimmer of light from within the snow pile.","TWN":"搬一搬發現那邊的雪堆裡發出微弱的光。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"빛이라고?","JPN":"光？","ENG":"Did you say, light?","TWN":"光？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"예, 그래서 땅을 파보려고 했더니 주변에서 마물들이 나타나더군요.","JPN":"はい、それを掘り出してみようとしたところ、魔物たちが集まってきたのです。","ENG":"Yes. So I was trying to dig it out, and then I got surrounded by monsters.","TWN":"是，所以我想挖開來看看，結果周圍開始出現怪物。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그치만, 할아범이 말한 빛이란 거. 아무데도 안 보이는데?","JPN":"でも、おじいちゃんが見たっていう光なんか、どこにも見えないけど？","ENG":"But I don't see any light around here, Kian.","TWN":"但我沒看到你說的那道光？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"그러게 말입니다.","JPN":"確かにそうですね。","ENG":"How odd.","TWN":"是啊。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"이 늙은이가 눈이 침침해서 착각이라도 한 건지…","JPN":"私も歳を取りましたので、老眼のせいで錯覚してしまったのかもしれませんね……","ENG":"Perhaps this old man's eyes were mistaken.","TWN":"不知道是不是我老眼昏花…"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"방금 이쯤이라고 했었지?","JPN":"この辺なのよね？","ENG":"You said it was around here, right?","TWN":"你說在這裡看到的嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그 삽 줘봐.","JPN":"そのシャベルを貸してみて。","ENG":"Hand me that shovel.","TWN":"把鏟子給我。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"잠깐만요, 아가씨.","JPN":"待ってください、お嬢様。","ENG":"Hold on, Miss Morgana.","TWN":"小姐等等。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L31_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"뭔가 보입니다.","JPN":"何かが見えます。","ENG":"I think I see something.","TWN":"好像有什麼東西。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"깜짝이야. 뭐야, 저건…?","JPN":"ひやっ！？　何、これ……？","ENG":"Whoa! What is that...?","TWN":"嚇我一跳。這是什麼…？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"얼어붙은 시체인가?","JPN":"凍結した死体？","ENG":"A frozen corpse?","TWN":"是結冰的屍體嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"시체가 아닙니다. 희미하지만 숨은 아직 쉬고 있군요.","JPN":"死体ではありません。弱いですが、息がまだあるようです。","ENG":"She is not a corpse. It's faint, but she is still breathing.","TWN":"人還沒死，還有微弱的呼吸。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"뭐?! 이런 데 파묻히고서 아직 살아 있다고?!","JPN":"えっ？　こんなところに埋もれていたのに、まだ生きているというの？","ENG":"What?! She's still alive after being buried in a place like this?!","TWN":"什麼？！被埋在這種地方還沒死？！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L37_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"설마… 사람으로 둔갑한 악마는 아니겠지?","JPN":"もしかして……人の皮を被った悪魔だったりして？","ENG":"You don't think... that she's a devil disguised as a person, right?","TWN":"該不會是…偽裝成人類的魔鬼吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"확신할 길은 없지만, 겉으로 보기엔 악마는 아니군요.","JPN":"確かなことは言えませんが、パッと見は悪魔のようには見えませんね。","ENG":"We can't be sure, but from just her looks, she doesn't seem to be a devil.","TWN":"雖然我也不確定，但外表看起來不像是魔鬼。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_05"},{"id":"L40_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"다칠 수도 있으니 지금부턴 손으로 꺼내겠어!","JPN":"怪我をしないように、ここからは素手で掘り出すわよ！","ENG":"I might hurt her, so I'll have to dig her out with my hands!","TWN":"接下來用手挖吧，我怕鏟子會傷到人！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_05"},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"할아범! 담요 같은 거 없어?","JPN":"おじいちゃん！　毛布とかない？","ENG":"Kian! Do you have a blanket or something?","TWN":"奇恩爺爺！我們有毯子嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":null,"text":{"KOREA":"잠시만 기다리십시오! 가져오겠습니다!","JPN":"少々お待ちください！　すぐに持ってきます！","ENG":"Just a moment! I'll bring it over!","TWN":"等我一下，我去拿！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"헥, 헤엑.","JPN":"はあ……ふうっ……","ENG":"*Huff* *Huff*","TWN":"呼，呼呼。"},"stage":{"bg":"ROOT_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"뭐가 이렇게 깊어? 이런 눈더미에 사람이 갇혀 있었다고?","JPN":"雪が深すぎない？　こんな雪の山に人が埋もれていたなんて……","ENG":"She's in there deep. How can a person be trapped so deep in the snow?","TWN":"會不會埋太深？怎麼會有人被埋在這麼深的雪堆裡？"},"stage":{"bg":"ROOT_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"야! 내 말 들려?","JPN":"ねえ！　聞こえる！？","ENG":"Hey! Can you hear me?","TWN":"喂！有聽到我的聲音嗎？"},"stage":{"bg":"ROOT_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L1_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"앗? 방금 나랑 눈 마주친 거 맞지?! 정신 놓으면 안 돼!","JPN":"あっ！　今目が合ったよね！？　気を失っちゃダメ！","ENG":"Huh? You just made eye contact with me, right?! Just don't go back to sleep!","TWN":"喂！你剛有和我對到眼吧？！不可以睡！"},"stage":{"bg":"ROOT_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"지금부터 당길 테니까! 힘 꽉 줘!","JPN":"今から引っ張り出すからね！　力入れてよ！","ENG":"I'm going to pull you out now! So hang on tight!","TWN":"我現在要拉你出來！你要抓緊我的手！"},"stage":{"bg":"ROOT_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"경고했다? 팔 빠져도 어쩔 수 없으니까!","JPN":"忠告はしたから！　腕が抜けても知らないからね！","ENG":"But I'm warning you! Don't cry if your arm gets dislocated!","TWN":"但我先警告你喔，手臂骨折的話我可不負責喔！"},"stage":{"bg":"ROOT_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"하나, 둘…!","JPN":"せーの……！","ENG":"One, two...!","TWN":"一、二…！"},"stage":{"bg":"ROOT_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};